function MkSl([string]$href, [string]$svg, [string]$label) {
    return "<a href=""$href"" class=""sidebar-link"">$svg$label</a>"
}
function MkRc([string]$href, [string]$label, [string]$title, [string]$desc) {
    return "<a href=""$href"" class=""related-card reveal""><span class=""related-card-label"">$label</span><h4>$title</h4><p>$desc</p><span class=""related-card-arrow"" data-i18n=""proj.detail.view"">View Project &rarr;</span></a>"
}

function MkPage {
    param([string]$f,[string]$pn,[string]$pt,[string]$md,[string]$hlEN,[string]$hlPT,[string]$bc,
          [string]$yr,[string]$prov,[string]$cl,[string]$fund,[string]$sec,[string]$svd,[string]$tgs,
          [string]$oEN,[string]$oPT,[string]$scEN,[string]$scPT,[string]$evEN,[string]$evPT,
          [string]$rEN,[string]$rPT,[string]$svl,[string]$rel)

    $h = "<!DOCTYPE html>`n<html lang=""en""><head>`n<meta charset=""UTF-8"" />`n<meta name=""viewport"" content=""width=device-width, initial-scale=1.0"" />`n<meta name=""description"" content=""$md"" />`n<title>$pt | Enviestudos Projects</title>`n<link rel=""preconnect"" href=""https://fonts.googleapis.com"" /><link rel=""preconnect"" href=""https://fonts.gstatic.com"" crossorigin />`n<link href=""https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;800&amp;family=Inter:wght@300;400;500;600&amp;display=swap"" rel=""stylesheet"" />`n<link rel=""stylesheet"" href=""css/style.css"" />`n</head><body>`n$nav`n<header class=""page-hero""><div class=""container""><div class=""page-hero-content""><div class=""page-hero-label""><span class=""lang-en"">$hlEN</span><span class=""lang-pt"">$hlPT</span></div><h1 data-i18n=""proj.p$pn.title""></h1><div class=""proj-hero-meta""><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.year"">Year</span><span class=""proj-hero-meta-value"">$yr</span></div><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.province"">Province</span><span class=""proj-hero-meta-value"">$prov</span></div><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.client"">Client</span><span class=""proj-hero-meta-value"">$cl</span></div><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.funder"">Funder</span><span class=""proj-hero-meta-value"">$fund</span></div></div><nav class=""breadcrumb"" aria-label=""Breadcrumb"" style=""margin-top:1.5rem;""><a href=""index.html"" data-i18n=""bc.home"">Home</a><span>&rsaquo;</span><a href=""projects.html"" data-i18n=""nav.projects"">Projects</a><span>&rsaquo;</span><span>$bc</span></nav></div></div></header>`n<section class=""section-pad"" style=""background:var(--clr-white);""><div class=""container""><div class=""detail-layout""><div class=""detail-body reveal""><h2 data-i18n=""proj.detail.overview"">Project Overview</h2><div class=""lang-en"">$oEN</div><div class=""lang-pt"">$oPT</div><h2 data-i18n=""proj.detail.scope"">Scope of Work</h2><div class=""lang-en""><ul>$scEN</ul></div><div class=""lang-pt""><ul>$scPT</ul></div><h2 data-i18n=""proj.detail.enviro"">Environmental Considerations</h2><div class=""lang-en""><ul>$evEN</ul></div><div class=""lang-pt""><ul>$evPT</ul></div><h2 data-i18n=""proj.detail.results"">Results &amp; Impact</h2><div class=""lang-en""><p>$rEN</p></div><div class=""lang-pt""><p>$rPT</p></div><div class=""tags-row"" style=""margin-top:1.5rem;"">$tgs</div></div><aside class=""detail-sidebar reveal reveal-delay-2""><div class=""sidebar-card""><div class=""sidebar-card-title"" data-i18n=""proj.detail.details"">Project Details</div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.sector"">Sector</span><span class=""sidebar-row-value"">$sec</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.year"">Year</span><span class=""sidebar-row-value"">$yr</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.province"">Province</span><span class=""sidebar-row-value"">$prov</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.client"">Client</span><span class=""sidebar-row-value"">$cl</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.funder"">Funder</span><span class=""sidebar-row-value"">$fund</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.svc-del"">Services Delivered</span><span class=""sidebar-row-value"">$svd</span></div></div><div class=""sidebar-card""><div class=""sidebar-card-title"" data-i18n=""proj.detail.svc-links"">Related Services</div><div class=""sidebar-links"">$svl</div></div></aside></div></div></section>`n<section class=""section-pad"" style=""background:var(--clr-light-bg);""><div class=""container""><div class=""text-center reveal""><div class=""section-label"" data-i18n=""proj.detail.more"">More Projects</div><h2 class=""section-title"" data-i18n=""proj.detail.related"">Related Case Studies</h2></div><div class=""related-grid"" style=""margin-top:2rem;"">$rel</div></div></section>`n<section class=""cta-section section-pad""><div class=""container""><div class=""cta-inner reveal""><div class=""section-label"" data-i18n=""proj.cta.label"">Let's Work Together</div><h2 data-i18n=""proj.cta.title"">Ready to Add Your Project to Our Portfolio?</h2><p data-i18n=""proj.cta.desc"">Contact us today to discuss your project's environmental requirements.</p><div class=""cta-actions""><a href=""contact.html"" class=""btn btn-primary"" data-i18n=""proj.cta.btn1"">Start a Conversation</a><a href=""projects.html"" class=""btn btn-outline"" data-i18n=""proj.detail.all"">All Projects</a></div></div></div></section>`n$foot`n</body></html>"
    [System.IO.File]::WriteAllText("$dir\$f", $h, (New-Object System.Text.UTF8Encoding($false)))
    Write-Host "OK: $f"
}

# ─── Project 12: Alto Molocue Rural Electrification ───
MkPage -f "project-alto-molocue.html" -pn "12" `
  -pt "ESIA Rural Electrification, Alto Molocue District, Zambezia" `
  -md "ESIA for rural electrification project in Alto Molocue District, Zambezia Province, India Bank financed — Enviestudos." `
  -hlEN "Energy &bull; Zambezia Province" -hlPT "Energia &bull; Prov&iacute;ncia da Zamb&eacute;zia" `
  -bc "Alto Molocue Rural Electrification ESIA" -yr "2006" -prov "Zambezia" `
  -cl "Mohan Exports, India" -fund "Indian Bank" -sec "Energy" `
  -svd "ESIA &bull; ToR &bull; EMP &bull; Public Consultations" `
  -tgs '<span class="project-tag">Indian Bank</span><span class="project-tag">ESIA</span><span class="project-tag">Rural Electrification</span><span class="project-tag">Zambezia</span><span class="project-tag">Energy Access</span>' `
  -oEN "<p>Enviestudos prepared the Environmental and Social Impact Assessment (ESIA) for a rural electrification project in Alto Molocue District, Zambezia Province, financed by the Indian Bank and contracted through Mohan Exports (India). The project aimed to extend electricity access to rural communities in one of Zambezia Province&rsquo;s interior districts.</p><p>This assignment was conducted in a period of expanding rural energy access in Mozambique, with the ESIA addressing the environmental and social implications of new distribution infrastructure extending to previously unserved rural areas.</p>" `
  -oPT "<p>A Enviestudos elaborou o Estudo de Impacto Ambiental e Social (EIA) para um projecto de electrifica&ccedil;&atilde;o rural no Distrito de Alto Molocue, Prov&iacute;ncia da Zamb&eacute;zia, financiado pelo Banco Indiano e contratado pela Mohan Exports (&Iacute;ndia). O projecto visava estender o acesso &agrave; electricidade a comunidades rurais num dos distritos do interior da Prov&iacute;ncia da Zamb&eacute;zia.</p><p>Esta miss&atilde;o foi realizada num per&iacute;odo de expans&atilde;o do acesso a energia rural em Mo&ccedil;ambique, com o EIA a abordar as implica&ccedil;&otilde;es ambientais e sociais da nova infraestrutura de distribui&ccedil;&atilde;o que se estendia a &aacute;reas rurais anteriormente n&atilde;o servidas.</p>" `
  -scEN "<li>Terms of Reference (ToR) preparation and submission to environmental authorities</li><li>Environmental baseline surveys along distribution line corridors</li><li>Socioeconomic baseline assessment of communities along the proposed route</li><li>Public consultation meetings in Alto Molocue District communities</li><li>Impact assessment for construction and operation of electricity distribution infrastructure</li><li>Environmental Management Plan (EMP) preparation</li><li>Final ESIA Report preparation</li>" `
  -scPT "<li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia (ToR) e submiss&atilde;o &agrave;s autoridades ambientais</li><li>Levantamentos de base ambiental ao longo dos corredores de linhas de distribui&ccedil;&atilde;o</li><li>Avalia&ccedil;&atilde;o socioecon&oacute;mica de base das comunidades ao longo do trajecto proposto</li><li>Reuni&otilde;es de consulta p&uacute;blica nas comunidades do Distrito de Alto Molocue</li><li>Avalia&ccedil;&atilde;o de impacto para a constru&ccedil;&atilde;o e opera&ccedil;&atilde;o de infraestrutura de distribui&ccedil;&atilde;o de electricidade</li><li>Elabora&ccedil;&atilde;o do Plano de Gest&atilde;o Ambiental (PGA)</li><li>Elabora&ccedil;&atilde;o do Relat&oacute;rio Final de EIA</li>" `
  -evEN "<li><strong>Line corridor impacts:</strong> Vegetation clearance along transmission and distribution line corridors and habitat fragmentation considerations.</li><li><strong>Agricultural land:</strong> Impacts on smallholder agricultural land crossed by distribution infrastructure and access tracks.</li><li><strong>Community health and safety:</strong> Electrical safety risks during construction and operation in communities with limited prior experience of electricity.</li><li><strong>Cultural heritage:</strong> Survey of cultural assets potentially affected by infrastructure routing.</li>" `
  -evPT "<li><strong>Impactos do corredor de linha:</strong> Desmatamento ao longo dos corredores de linhas de transmiss&atilde;o e distribui&ccedil;&atilde;o e considera&ccedil;&otilde;es sobre fragmenta&ccedil;&atilde;o de habitats.</li><li><strong>Terra agr&iacute;cola:</strong> Impactos nas terras agr&iacute;colas familiares atravessadas pela infraestrutura de distribui&ccedil;&atilde;o e vias de acesso.</li><li><strong>Sa&uacute;de e seguran&ccedil;a comunit&aacute;ria:</strong> Riscos de seguran&ccedil;a el&eacute;ctrica durante a constru&ccedil;&atilde;o e opera&ccedil;&atilde;o em comunidades com experi&ecirc;ncia limitada de electricidade.</li><li><strong>Patrim&oacute;nio cultural:</strong> Levantamento de bens culturais potencialmente afectados pelo tra&ccedil;ado da infraestrutura.</li>" `
  -rEN "The ESIA provided the Indian Bank and Mohan Exports with the environmental regulatory approval required to proceed with the Alto Molocue rural electrification project, contributing to improved energy access for rural communities in Zambezia Province." `
  -rPT "O EIA forneceu ao Banco Indiano e &agrave; Mohan Exports a aprova&ccedil;&atilde;o regulat&oacute;ria ambiental necess&aacute;ria para avan&ccedil;ar com o projecto de electrifica&ccedil;&atilde;o rural do Alto Molocue, contribuindo para a melhoria do acesso &agrave; energia para as comunidades rurais da Prov&iacute;ncia da Zamb&eacute;zia." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-milange-esia.html' 'Roads &amp; Bridges &bull; 2007&ndash;2008' 'ESIA &mdash; Milange&ndash;Mocuba Road Upgrading' 'Comprehensive ESIA for EU-financed road upgrading in Zambezia Province, prepared for BCEOM.')$(MkRc 'project-en1-namacurra.html' 'Roads &amp; Bridges &bull; 2005&ndash;2008' 'ESIA Supervision &mdash; EN1, Namacurra&ndash;Rio Ligonha' 'Three-year ESIA supervision for EU-financed EN1 road rehabilitation in Zambezia Province.')"

# ─── Project 13: ANE Gaza Floods ───
MkPage -f "project-ane-gaza.html" -pn "13" `
  -pt "Technical Support to ANE, Gaza Province Flood Damage Assessment" `
  -md "Technical support to ANE Gaza Province for flood damage assessment and prioritisation, World Bank emergency project — Enviestudos." `
  -hlEN "Technical Assistance &bull; Gaza Province" -hlPT "Assist&ecirc;ncia T&eacute;cnica &bull; Prov&iacute;ncia de Gaza" `
  -bc "Technical Support ANE Gaza Province" -yr "2015&ndash;2016" -prov "Gaza" `
  -cl "SMEC International" -fund "World Bank" -sec "Technical Assistance" `
  -svd "Environmental Advisor &bull; Social Safeguards &bull; Reporting" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">Technical Assistance</span><span class="project-tag">Flood Response</span><span class="project-tag">Gaza</span><span class="project-tag">ANE</span>' `
  -oEN "<p>Enviestudos provided environmental and social technical support to the National Roads Administration (ANE) in Gaza Province following severe flood events that damaged road infrastructure. The assignment was part of a World Bank-financed emergency infrastructure response project, contracted through SMEC International.</p><p>The role involved providing environmental and social safeguards advisory services to ensure flood rehabilitation works met World Bank requirements, including screening of rehabilitation sub-projects for environmental and social impacts.</p>" `
  -oPT "<p>A Enviestudos prestou apoio t&eacute;cnico ambiental e social &agrave; Administra&ccedil;&atilde;o Nacional de Estradas (ANE) na Prov&iacute;ncia de Gaza na sequ&ecirc;ncia de graves eventos de cheia que danificaram a infraestrutura rodovi&aacute;ria. A miss&atilde;o fez parte de um projecto de resposta a infraestrutura de emerg&ecirc;ncia financiado pelo Banco Mundial, contratado atrav&eacute;s da SMEC International.</p><p>A fun&ccedil;&atilde;o envolveu a presta&ccedil;&atilde;o de servi&ccedil;os consultivos de salvaguardas ambientais e sociais para garantir que as obras de reabilita&ccedil;&atilde;o de cheias cumprissem os requisitos do Banco Mundial, incluindo a triagem de sub-projectos de reabilita&ccedil;&atilde;o quanto a impactos ambientais e sociais.</p>" `
  -scEN "<li>Environmental and social screening of flood damage rehabilitation sub-projects</li><li>Provision of Environmental Checklists for rehabilitation works at individual sites</li><li>Technical support to ANE Gaza Province environmental staff on World Bank safeguards</li><li>Review and quality assurance of environmental documentation for rehabilitation works</li><li>Site visits to damaged road infrastructure for environmental damage documentation</li><li>Periodic environmental compliance reporting to the World Bank</li>" `
  -scPT "<li>Triagem ambiental e social de sub-projectos de reabilita&ccedil;&atilde;o de danos de cheia</li><li>Elabora&ccedil;&atilde;o de Listas de Verifica&ccedil;&atilde;o Ambientais para obras de reabilita&ccedil;&atilde;o em locais individuais</li><li>Apoio t&eacute;cnico &agrave; equipa de ambiente da ANE Gaza sobre salvaguardas do Banco Mundial</li><li>Revis&atilde;o e garantia de qualidade da documenta&ccedil;&atilde;o ambiental para obras de reabilita&ccedil;&atilde;o</li><li>Visitas de campo a infraestrutura rodovi&aacute;ria danificada para documenta&ccedil;&atilde;o de danos ambientais</li><li>Relat&oacute;rios peri&oacute;dicos de conformidade ambiental para o Banco Mundial</li>" `
  -evEN "<li><strong>Flood-affected corridors:</strong> Environmental assessment of road sections in flood-prone areas of Gaza Province requiring resilience-focused rehabilitation design.</li><li><strong>River crossing vulnerability:</strong> Assessment of bridge and culvert damage from flood events and environmental requirements for repair and reinforcement.</li><li><strong>Community safety:</strong> Road access restoration for communities isolated by flood damage to road infrastructure.</li><li><strong>Ecosystem recovery:</strong> Consideration of natural channel restoration alongside road rehabilitation measures.</li>" `
  -evPT "<li><strong>Corredores afectados por cheias:</strong> Avalia&ccedil;&atilde;o ambiental de sec&ccedil;&otilde;es de estrada em &aacute;reas sujeitas a cheias da Prov&iacute;ncia de Gaza que requerem projecto de reabilita&ccedil;&atilde;o orientado para a resili&ecirc;ncia.</li><li><strong>Vulnerabilidade das travessias fluviais:</strong> Avalia&ccedil;&atilde;o dos danos causados pelas cheias em pontes e aquedutos e requisitos ambientais para repara&ccedil;&atilde;o e refor&ccedil;o.</li><li><strong>Seguran&ccedil;a comunit&aacute;ria:</strong> Restaura&ccedil;&atilde;o do acesso rodovi&aacute;rio para comunidades isoladas pelos danos das cheias na infraestrutura rodovi&aacute;ria.</li><li><strong>Recupera&ccedil;&atilde;o do ecossistema:</strong> Considera&ccedil;&atilde;o da restaura&ccedil;&atilde;o natural dos canais a par das medidas de reabilita&ccedil;&atilde;o rodovi&aacute;ria.</li>" `
  -rEN "Technical environmental and social support enabled ANE Gaza Province to respond to flood infrastructure damage in compliance with World Bank safeguard requirements, contributing to faster and more environmentally sound road rehabilitation in flood-affected communities across Gaza Province." `
  -rPT "O apoio t&eacute;cnico ambiental e social permitiu &agrave; ANE Gaza responder aos danos na infraestrutura causados pelas cheias em conformidade com os requisitos de salvaguarda do Banco Mundial, contribuindo para uma reabilita&ccedil;&atilde;o rodovi&aacute;ria mais r&aacute;pida e ambientalmente adequada nas comunidades afectadas pelas cheias em toda a Prov&iacute;ncia de Gaza." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-audit.html' $svgEsia 'Environmental Audits')" `
  -rel "$(MkRc 'project-chongoene.html' 'Infrastructure &bull; 2022' 'ESIA &mdash; Port Infrastructure, Chongoene, Gaza' 'Full ESIA for new port infrastructure in Gaza Province, funded by World Bank.')$(MkRc 'project-n103-roads.html' 'Roads &amp; Bridges &bull; 2014&ndash;2016' 'EHS Supervision &mdash; Roads N103 and R657' 'EHS supervision for road rehabilitation works across Zambezia and Niassa provinces, World Bank.')"

# ─── Project 14: Milange Phase II Lot 2 ───
MkPage -f "project-milange-lot2.html" -pn "14" `
  -pt "EHS Supervision, Milange-Mocuba Phase II Lot 2, Zambezia" `
  -md "EHS supervision for Milange-Mocuba Road Corridor Phase II Lot 2 construction, EU-financed — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Zambezia Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia da Zamb&eacute;zia" `
  -bc "Milange-Mocuba EHS Supervision, Phase II Lot 2" -yr "2015" -prov "Zambezia" `
  -cl "Nicholas O&rsquo;Dwyer Ltd" -fund "European Union" -sec "Roads &amp; Bridges" `
  -svd "EHS Supervision &bull; Non-conformance Reporting &bull; ESMP Monitoring" `
  -tgs '<span class="project-tag">EU</span><span class="project-tag">EHS Supervision</span><span class="project-tag">Zambezia</span><span class="project-tag">Roads</span><span class="project-tag">ESMP</span>' `
  -oEN "<p>Enviestudos provided Environmental Health and Safety (EHS) supervision services for Lot 2 of the Milange-Mocuba Road Corridor Phase II civil works in Zambezia Province, financed by the European Union and contracted through Nicholas O&rsquo;Dwyer Ltd.</p><p>The assignment involved continuous monitoring of the construction contractor&rsquo;s environmental and social performance against the approved ESIA and ESMP throughout the construction period, with non-conformance tracking and reporting.</p>" `
  -oPT "<p>A Enviestudos prestou servi&ccedil;os de supervis&atilde;o de Sa&uacute;de, Seguran&ccedil;a e Ambiente (HSA) para o Lote 2 das obras civis da Fase II do Corredor Milange-Mocuba na Prov&iacute;ncia da Zamb&eacute;zia, financiados pela Uni&atilde;o Europeia e contratados atrav&eacute;s da Nicholas O&rsquo;Dwyer Ltd.</p><p>A miss&atilde;o envolveu a monitoriza&ccedil;&atilde;o cont&iacute;nua do desempenho ambiental e social do empreiteiro de constru&ccedil;&atilde;o face ao EIA e PGAS aprovados durante o per&iacute;odo de constru&ccedil;&atilde;o, com registo e relato de n&atilde;o-conformidades.</p>" `
  -scEN "<li>Continuous EHS field monitoring of contractor activities on Lot 2 works</li><li>Verification of ESMP mitigation measure implementation by the contractor</li><li>Site inspections of borrow pits, quarries, construction camps, and disposal areas</li><li>Non-conformance identification, recording, and follow-up to closure</li><li>Community liaison and grievance monitoring along the road corridor</li><li>Health and safety performance monitoring and incident reporting</li><li>Preparation of periodic EHS supervision reports for the EU</li>" `
  -scPT "<li>Monitoriza&ccedil;&atilde;o cont&iacute;nua de HSA das actividades do empreiteiro nas obras do Lote 2</li><li>Verifica&ccedil;&atilde;o da implementa&ccedil;&atilde;o das medidas de mitiga&ccedil;&atilde;o do PGAS pelo empreiteiro</li><li>Inspec&ccedil;&otilde;es de campo a zonas de empr&eacute;stimo, pedreiras, acampamentos de constru&ccedil;&atilde;o e &aacute;reas de dep&oacute;sito</li><li>Identifica&ccedil;&atilde;o, registo e seguimento de n&atilde;o-conformidades at&eacute; ao encerramento</li><li>Liga&ccedil;&atilde;o comunit&aacute;ria e monitoriza&ccedil;&atilde;o de queixas ao longo do corredor rodovi&aacute;rio</li><li>Monitoriza&ccedil;&atilde;o do desempenho de sa&uacute;de e seguran&ccedil;a e relato de incidentes</li><li>Elabora&ccedil;&atilde;o de relat&oacute;rios peri&oacute;dicos de supervis&atilde;o HSA para a UE</li>" `
  -evEN "<li><strong>Borrow pit management:</strong> Monitoring of progressive rehabilitation and appropriate management of extraction sites throughout the works period.</li><li><strong>Erosion and drainage:</strong> Construction-phase earthworks, slope management, and drainage protection monitoring.</li><li><strong>Community impacts:</strong> Construction traffic, noise, and dust management in roadside communities along Lot 2.</li><li><strong>Biodiversity protection:</strong> Compliance with vegetation clearing restrictions and protection of trees and habitats outside the approved clearing envelope.</li>" `
  -evPT "<li><strong>Gest&atilde;o de zonas de empr&eacute;stimo:</strong> Monitoriza&ccedil;&atilde;o da reabilita&ccedil;&atilde;o progressiva e gest&atilde;o adequada dos locais de extra&ccedil;&atilde;o durante o per&iacute;odo de obras.</li><li><strong>Eros&atilde;o e drenagem:</strong> Monitoriza&ccedil;&atilde;o de movimentos de terra, gest&atilde;o de taludes e prote&ccedil;&atilde;o da drenagem na fase de constru&ccedil;&atilde;o.</li><li><strong>Impactos comunit&aacute;rios:</strong> Gest&atilde;o do tr&aacute;fego, ru&iacute;do e poeira de constru&ccedil;&atilde;o nas comunidades marginais do Lote 2.</li><li><strong>Prote&ccedil;&atilde;o da biodiversidade:</strong> Conformidade com as restri&ccedil;&otilde;es de desmatamento e prote&ccedil;&atilde;o de &aacute;rvores e habitats fora do envelope de corte aprovado.</li>" `
  -rEN "EHS supervision throughout the Milange-Mocuba Phase II Lot 2 works maintained EU environmental compliance standards, contributing to the successful and environmentally sound completion of this important transport corridor in Zambezia Province." `
  -rPT "A supervis&atilde;o HSA ao longo das obras do Lote 2 da Fase II do Milange-Mocuba manteve os padr&otilde;es de conformidade ambiental da UE, contribuindo para a conclus&atilde;o bem-sucedida e ambientalmente adequada deste importante corredor de transportes na Prov&iacute;ncia da Zamb&eacute;zia." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')" `
  -rel "$(MkRc 'project-milange-decommission.html' 'Roads &amp; Bridges &bull; 2019' 'Environmental Decommissioning &mdash; Milange-Mocuba Phase II' 'Decommissioning inspection of all construction sites after completion of Phase II works.')$(MkRc 'project-milange-esia.html' 'Roads &amp; Bridges &bull; 2007&ndash;2008' 'ESIA &mdash; Milange&ndash;Mocuba Road Upgrading' 'Comprehensive ESIA for EU-financed Milange-Mocuba Road upgrading, prepared for BCEOM.')"

# ─── Project 15: N14 Supervision ───
MkPage -f "project-n14-supervision.html" -pn "15" `
  -pt "Environmental Supervision, N14 Road, Marrupa-Rua&ccedil;a, Lot B, Niassa" `
  -md "Health and Safety supervision for N14 Road civil works, Marrupa to Ruaca Lot B, World Bank financed, Niassa — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Niassa Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia do Niassa" `
  -bc "N14 Road Supervision, Marrupa&ndash;Rua&ccedil;a" -yr "Oct&ndash;Nov 2011" -prov "Niassa" `
  -cl "EGIS International / BCEOM" -fund "World Bank" -sec "Roads &amp; Bridges" `
  -svd "H&amp;S Supervision &bull; Site Inspection &bull; Report" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">Supervision</span><span class="project-tag">N14 Road</span><span class="project-tag">Niassa</span><span class="project-tag">Health &amp; Safety</span>' `
  -oEN "<p>Enviestudos provided Health and Safety supervision services for Lot B of the N14 Road rehabilitation project from Marrupa to Rua&ccedil;a in Niassa Province, contracted through EGIS International / BCEOM and financed by the World Bank. The assignment covered a focused supervision period during a critical phase of the civil works.</p><p>The N14 road is a key northern Mozambique corridor linking isolated communities in Niassa Province to provincial services and markets. The Marrupa&ndash;Rua&ccedil;a section passes through remote areas with limited infrastructure.</p>" `
  -oPT "<p>A Enviestudos prestou servi&ccedil;os de supervis&atilde;o de Sa&uacute;de e Seguran&ccedil;a para o Lote B do projecto de reabilita&ccedil;&atilde;o da Estrada N14 de Marrupa a Rua&ccedil;a na Prov&iacute;ncia do Niassa, contratado atrav&eacute;s da EGIS International / BCEOM e financiado pelo Banco Mundial. A miss&atilde;o abrangeu um per&iacute;odo focado de supervis&atilde;o durante uma fase cr&iacute;tica das obras civis.</p><p>A estrada N14 &eacute; um corredor chave do norte de Mo&ccedil;ambique que liga comunidades isoladas na Prov&iacute;ncia do Niassa a servi&ccedil;os provinciais e mercados. A sec&ccedil;&atilde;o Marrupa&ndash;Rua&ccedil;a atravessa &aacute;reas remotas com infraestrutura limitada.</p>" `
  -scEN "<li>Health and safety site inspections across Lot B of the N14 rehabilitation works</li><li>Review of contractor Health and Safety plans and procedures</li><li>Verification of personal protective equipment use by construction workforce</li><li>Site safety audit of construction areas, equipment, and working practices</li><li>Incident documentation and corrective action tracking</li><li>Final Health and Safety supervision report preparation</li>" `
  -scPT "<li>Inspec&ccedil;&otilde;es de sa&uacute;de e seguran&ccedil;a no Lote B das obras de reabilita&ccedil;&atilde;o da N14</li><li>Revis&atilde;o dos planos e procedimentos de sa&uacute;de e seguran&ccedil;a do empreiteiro</li><li>Verifica&ccedil;&atilde;o do uso de equipamentos de prote&ccedil;&atilde;o individual pela for&ccedil;a de trabalho</li><li>Auditoria de seguran&ccedil;a de locais de constru&ccedil;&atilde;o, equipamentos e pr&aacute;ticas de trabalho</li><li>Documenta&ccedil;&atilde;o de incidentes e seguimento de ac&ccedil;&otilde;es correctivas</li><li>Elabora&ccedil;&atilde;o do relat&oacute;rio final de supervis&atilde;o de Sa&uacute;de e Seguran&ccedil;a</li>" `
  -evEN "<li><strong>Remote works safety:</strong> Health and safety compliance in remote areas with limited access to medical facilities for the construction workforce.</li><li><strong>Heavy equipment operations:</strong> Safe operation of earthmoving and road construction equipment on rural road corridors.</li><li><strong>Community road safety:</strong> Traffic management and community safety at road construction zones on the active N14 corridor.</li><li><strong>Occupational health:</strong> Dust, noise, and vibration monitoring for construction worker occupational health protection.</li>" `
  -evPT "<li><strong>Seguran&ccedil;a em obras remotas:</strong> Conformidade com sa&uacute;de e seguran&ccedil;a em &aacute;reas remotas com acesso limitado a instala&ccedil;&otilde;es m&eacute;dicas para a for&ccedil;a de trabalho.</li><li><strong>Opera&ccedil;&otilde;es de equipamento pesado:</strong> Opera&ccedil;&atilde;o segura de equipamento de movimenta&ccedil;&atilde;o de terras e constru&ccedil;&atilde;o rodovi&aacute;ria em corredores rurais.</li><li><strong>Seguran&ccedil;a rodovi&aacute;ria comunit&aacute;ria:</strong> Gest&atilde;o de tr&aacute;fego e seguran&ccedil;a comunit&aacute;ria nas zonas de constru&ccedil;&atilde;o no corredor activo da N14.</li><li><strong>Sa&uacute;de ocupacional:</strong> Monitoriza&ccedil;&atilde;o de poeira, ru&iacute;do e vibra&ccedil;&atilde;o para prote&ccedil;&atilde;o da sa&uacute;de ocupacional dos trabalhadores.</li>" `
  -rEN "Health and Safety supervision of the N14 Lot B works ensured construction activities met World Bank and Mozambican occupational health and safety requirements, contributing to a safe working environment for the construction workforce in this remote Niassa Province corridor." `
  -rPT "A supervis&atilde;o de Sa&uacute;de e Seguran&ccedil;a das obras do Lote B da N14 garantiu que as actividades de constru&ccedil;&atilde;o cumprissem os requisitos de sa&uacute;de e seguran&ccedil;a ocupacional do Banco Mundial e de Mo&ccedil;ambique, contribuindo para um ambiente de trabalho seguro para a for&ccedil;a de trabalho neste corredor remoto da Prov&iacute;ncia do Niassa." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')" `
  -rel "$(MkRc 'project-n14-emp.html' 'Roads &amp; Bridges &bull; 2009' 'EMP Review &mdash; N14 Road Rehabilitation' 'Review of Environmental Management Plan for N14 road, World Bank financed, Niassa Province.')$(MkRc 'project-cuamba-road.html' 'Roads &amp; Bridges &bull; 2020&ndash;2021' 'ESIA &mdash; Cuamba Roads, Niassa Province' 'Full ESIA for Cuamba-Insaca and Cuamba-Metarica road reconstruction, World Bank financed.')"

# ─── Project 16: AIAS Water Supply ───
MkPage -f "project-aias-water.html" -pn "16" `
  -pt "Technical Assistance to AIAS, Water Supply and Sanitation" `
  -md "ESIA preparation and technical assistance for AIAS water supply and sanitation projects, World Bank financed — Enviestudos." `
  -hlEN "Water &amp; Sanitation &bull; Multiple Provinces" -hlPT "&Aacute;gua e Saneamento &bull; V&aacute;rias Prov&iacute;ncias" `
  -bc "Technical Assistance to AIAS, Water Supply" -yr "2011" -prov "Multiple Provinces" `
  -cl "Brisbane City Enterprises &amp; SMEC" -fund "World Bank" -sec "Water &amp; Sanitation" `
  -svd "ESIA &bull; Technical Assistance &bull; Capacity Building" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">ESIA</span><span class="project-tag">Water Supply</span><span class="project-tag">AIAS</span><span class="project-tag">Technical Assistance</span>' `
  -oEN "<p>Enviestudos provided environmental technical assistance to AIAS (Infrastructure and Water Supply Administration) for water supply and sanitation projects across multiple Mozambican provinces, under a World Bank-financed programme contracted through Brisbane City Enterprises and SMEC. The assignment involved preparing ESIA documentation and providing environmental safeguards capacity building to AIAS staff.</p><p>AIAS is responsible for developing water supply and sanitation infrastructure in secondary cities and towns across Mozambique. This technical assistance programme strengthened their institutional environmental management capacity.</p>" `
  -oPT "<p>A Enviestudos prestou assist&ecirc;ncia t&eacute;cnica ambiental ao AIAS (Administra&ccedil;&atilde;o de Infraestrutura de &Aacute;guas e Saneamento) para projectos de abastecimento de &aacute;gua e saneamento em v&aacute;rias prov&iacute;ncias mo&ccedil;ambicanas, ao abrigo de um programa financiado pelo Banco Mundial contratado atrav&eacute;s da Brisbane City Enterprises e SMEC. A miss&atilde;o envolveu a elabora&ccedil;&atilde;o de documenta&ccedil;&atilde;o de EIA e a constru&ccedil;&atilde;o de capacidade em salvaguardas ambientais para o pessoal do AIAS.</p><p>O AIAS &eacute; respons&aacute;vel pelo desenvolvimento de infraestrutura de abastecimento de &aacute;gua e saneamento nas cidades secund&aacute;rias e vilas de Mo&ccedil;ambique. Este programa de assist&ecirc;ncia t&eacute;cnica fortaleceu a sua capacidade institucional de gest&atilde;o ambiental.</p>" `
  -scEN "<li>Environmental screening of AIAS water supply and sanitation sub-projects</li><li>ESIA preparation for water supply infrastructure projects in multiple provinces</li><li>Environmental Management Plans for individual water supply sub-projects</li><li>Capacity building training for AIAS environmental staff on World Bank safeguard requirements</li><li>Quality review of environmental documentation produced by AIAS staff</li><li>Technical guidance on environmental monitoring and reporting systems</li>" `
  -scPT "<li>Triagem ambiental de sub-projectos de abastecimento de &aacute;gua e saneamento do AIAS</li><li>Elabora&ccedil;&atilde;o de EIA para projectos de infraestrutura de abastecimento de &aacute;gua em v&aacute;rias prov&iacute;ncias</li><li>Planos de Gest&atilde;o Ambiental para sub-projectos individuais de abastecimento de &aacute;gua</li><li>Forma&ccedil;&atilde;o de constru&ccedil;&atilde;o de capacidade para o pessoal ambiental do AIAS sobre requisitos de salvaguarda do Banco Mundial</li><li>Revis&atilde;o de qualidade da documenta&ccedil;&atilde;o ambiental produzida pelo pessoal do AIAS</li><li>Orienta&ccedil;&atilde;o t&eacute;cnica sobre sistemas de monitoriza&ccedil;&atilde;o e relato ambiental</li>" `
  -evEN "<li><strong>Source water protection:</strong> Environmental assessment of catchment areas and surface or groundwater source protection for new water supply schemes.</li><li><strong>Construction impacts:</strong> Environmental and social impacts of water supply and pipeline construction in urban and peri-urban settings.</li><li><strong>Groundwater sustainability:</strong> Assessment of aquifer sustainability for new borehole and well-based water supply projects.</li><li><strong>Community health outcomes:</strong> Positive health impact assessment of improved clean water access and sanitation coverage.</li>" `
  -evPT "<li><strong>Prote&ccedil;&atilde;o da &aacute;gua de abastecimento:</strong> Avalia&ccedil;&atilde;o ambiental das &aacute;reas de captamento e prote&ccedil;&atilde;o da fonte de &aacute;gua superficial ou subterr&acirc;nea para novos esquemas de abastecimento de &aacute;gua.</li><li><strong>Impactos da constru&ccedil;&atilde;o:</strong> Impactos ambientais e sociais da constru&ccedil;&atilde;o de abastecimento de &aacute;gua e conduta em contextos urbanos e peri-urbanos.</li><li><strong>Sustentabilidade das &aacute;guas subterr&acirc;neas:</strong> Avalia&ccedil;&atilde;o da sustentabilidade dos aqu&iacute;feros para novos projectos de abastecimento de &aacute;gua baseados em furos e po&ccedil;os.</li><li><strong>Resultados de sa&uacute;de comunit&aacute;ria:</strong> Avalia&ccedil;&atilde;o do impacto positivo na sa&uacute;de da melhoria do acesso &agrave; &aacute;gua potable e cobertura de saneamento.</li>" `
  -rEN "The technical assistance programme successfully provided AIAS with compliant environmental documentation for multiple water supply sub-projects while also strengthening the organisation&rsquo;s internal environmental management capacity to meet World Bank safeguard requirements on future projects." `
  -rPT "O programa de assist&ecirc;ncia t&eacute;cnica forneceu com sucesso ao AIAS documenta&ccedil;&atilde;o ambiental conforme para v&aacute;rios sub-projectos de abastecimento de &aacute;gua, ao mesmo tempo que fortaleceu a capacidade interna de gest&atilde;o ambiental da organiza&ccedil;&atilde;o para cumprir os requisitos de salvaguarda do Banco Mundial em projectos futuros." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-nacala-water.html' 'Water &amp; Sanitation &bull; 2016&ndash;2018' 'Environmental Supervision &mdash; Nacala Porto Water Supply' 'Environmental supervision for IDA-financed water supply rehabilitation in Nampula Province.')$(MkRc 'project-sanitation-cities.html' 'Water &amp; Sanitation &bull; 2010&ndash;2011' 'ESIA &mdash; Sanitation Improvements, Pemba, Nampula &amp; Quelimane' 'Multi-city ESIA for MCC-financed sanitation improvements across three Mozambican cities.')"

# ─── Project 17: N14 EMP ───
MkPage -f "project-n14-emp.html" -pn "17" `
  -pt "EMP Review, N14 Road Rehabilitation, Niassa Province" `
  -md "Review of Environmental Management Plan for N14 road rehabilitation, Niassa Province, World Bank financed — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Niassa Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia do Niassa" `
  -bc "N14 Road EMP Review" -yr "2009" -prov "Niassa" `
  -cl "BCEOM, France" -fund "World Bank" -sec "Roads &amp; Bridges" `
  -svd "EMP Review &bull; Gap Analysis &bull; Recommendations" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">EMP Review</span><span class="project-tag">N14 Road</span><span class="project-tag">Niassa</span><span class="project-tag">BCEOM</span>' `
  -oEN "<p>Enviestudos was commissioned by BCEOM (France) to review the Environmental Management Plan (EMP) for the N14 road rehabilitation project in Niassa Province, financed by the World Bank. The EMP review assessed the adequacy and completeness of the environmental and social mitigation and monitoring framework for the road rehabilitation works.</p><p>This early assignment in Enviestudos&rsquo; history reflects the firm&rsquo;s established expertise in World Bank environmental standards and the N14 road corridor in northern Mozambique, from which subsequent supervision assignments followed.</p>" `
  -oPT "<p>A Enviestudos foi contratada pela BCEOM (Fran&ccedil;a) para rever o Plano de Gest&atilde;o Ambiental (PGA) do projecto de reabilita&ccedil;&atilde;o da estrada N14 na Prov&iacute;ncia do Niassa, financiado pelo Banco Mundial. A revis&atilde;o do PGA avaliou a adequa&ccedil;&atilde;o e completude do quadro de mitiga&ccedil;&atilde;o ambiental e social e de monitoriza&ccedil;&atilde;o para as obras de reabilita&ccedil;&atilde;o da estrada.</p><p>Esta miss&atilde;o nos prim&oacute;rdios da Enviestudos reflecte a expertise estabelecida da empresa nas normas ambientais do Banco Mundial e no corredor rodovi&aacute;rio N14 no norte de Mo&ccedil;ambique, a que se seguiram posteriores miss&otilde;es de supervis&atilde;o.</p>" `
  -scEN "<li>Systematic review of the N14 EMP structure, content, and completeness</li><li>Gap analysis against World Bank OP 4.01 environmental safeguard requirements</li><li>Assessment of mitigation measures for adequacy and implementability</li><li>Review of environmental monitoring framework, indicators, and reporting requirements</li><li>Assessment of institutional arrangements for EMP implementation</li><li>Provision of specific recommendations for EMP improvement and update</li><li>EMP Review Report preparation</li>" `
  -scPT "<li>Revis&atilde;o sistem&aacute;tica da estrutura, conte&uacute;do e completude do PGA da N14</li><li>An&aacute;lise de lacunas face aos requisitos de salvaguarda ambiental OP 4.01 do Banco Mundial</li><li>Avalia&ccedil;&atilde;o das medidas de mitiga&ccedil;&atilde;o quanto &agrave; adequa&ccedil;&atilde;o e implementabilidade</li><li>Revis&atilde;o do quadro de monitoriza&ccedil;&atilde;o ambiental, indicadores e requisitos de relato</li><li>Avalia&ccedil;&atilde;o dos acordos institucionais para implementa&ccedil;&atilde;o do PGA</li><li>Presta&ccedil;&atilde;o de recomenda&ccedil;&otilde;es espec&iacute;ficas para melhoria e actualiza&ccedil;&atilde;o do PGA</li><li>Elabora&ccedil;&atilde;o do Relat&oacute;rio de Revis&atilde;o do PGA</li>" `
  -evEN "<li><strong>EMP completeness:</strong> Assessment of whether all significant environmental and social impacts of the N14 rehabilitation were adequately addressed in the EMP.</li><li><strong>Monitoring framework:</strong> Review of environmental monitoring indicators, measurement methods, and reporting frequency for adequacy.</li><li><strong>Institutional capacity:</strong> Assessment of contractor and supervision team capacity to implement the EMP requirements during works.</li><li><strong>World Bank compliance:</strong> Alignment of the EMP with World Bank OP 4.01 requirements applicable to the project.</li>" `
  -evPT "<li><strong>Completude do PGA:</strong> Avalia&ccedil;&atilde;o da adequa&ccedil;&atilde;o com que todos os impactos ambientais e sociais significativos da reabilita&ccedil;&atilde;o da N14 foram abordados no PGA.</li><li><strong>Quadro de monitoriza&ccedil;&atilde;o:</strong> Revis&atilde;o dos indicadores de monitoriza&ccedil;&atilde;o ambiental, m&eacute;todos de medi&ccedil;&atilde;o e frequ&ecirc;ncia de relato quanto &agrave; adequa&ccedil;&atilde;o.</li><li><strong>Capacidade institucional:</strong> Avalia&ccedil;&atilde;o da capacidade do empreiteiro e da equipa de supervis&atilde;o para implementar os requisitos do PGA durante as obras.</li><li><strong>Conformidade com o Banco Mundial:</strong> Alinhamento do PGA com os requisitos da OP 4.01 do Banco Mundial aplic&aacute;veis ao projecto.</li>" `
  -rEN "The EMP review provided BCEOM and the World Bank with a comprehensive gap analysis and actionable recommendations for strengthening the N14 road rehabilitation environmental management plan, contributing to improved environmental performance during subsequent construction works on the corridor." `
  -rPT "A revis&atilde;o do PGA forneceu &agrave; BCEOM e ao Banco Mundial uma an&aacute;lise de lacunas abrangente e recomenda&ccedil;&otilde;es vi&aacute;veis para o fortalecimento do plano de gest&atilde;o ambiental da reabilita&ccedil;&atilde;o da estrada N14, contribuindo para um melhor desempenho ambiental durante as obras de constru&ccedil;&atilde;o subsequentes no corredor." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-audit.html' $svgEsia 'Environmental Audits')" `
  -rel "$(MkRc 'project-n14-supervision.html' 'Roads &amp; Bridges &bull; 2011' 'Supervision &mdash; N14 Road, Marrupa&ndash;Rua&ccedil;a (Lot B)' 'Health and Safety supervision for N14 Road civil works in Niassa Province, World Bank financed.')$(MkRc 'project-cuamba-road.html' 'Roads &amp; Bridges &bull; 2020&ndash;2021' 'ESIA &mdash; Cuamba Roads, Niassa Province' 'Full ESIA for Cuamba-Insaca and Cuamba-Metarica road reconstruction, World Bank financed.')"

# ─── Project 18: Milange ESIA 2007-08 ───
MkPage -f "project-milange-esia.html" -pn "18" `
  -pt "ESIA Milange-Mocuba Road Upgrading, Zambezia Province" `
  -md "ESIA for Milange-Mocuba Road upgrading project, Zambezia Province, EU-financed, prepared for BCEOM — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Zambezia Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia da Zamb&eacute;zia" `
  -bc "Milange&ndash;Mocuba Road ESIA" -yr "2007&ndash;2008" -prov "Zambezia" `
  -cl "BCEOM, France" -fund "European Union" -sec "Roads &amp; Bridges" `
  -svd "ESIA &bull; ToR &bull; ESMP &bull; RAP &bull; Public Consultations" `
  -tgs '<span class="project-tag">EU</span><span class="project-tag">ESIA</span><span class="project-tag">ESMP</span><span class="project-tag">RAP</span><span class="project-tag">Zambezia</span>' `
  -oEN "<p>Enviestudos prepared the Environmental and Social Impact Assessment (ESIA) for the Milange-Mocuba road upgrading project in Zambezia Province, an EU-financed initiative contracted through BCEOM (France). This was one of the firm&rsquo;s significant early projects, demonstrating capability in comprehensive ESIA and resettlement planning for major infrastructure.</p><p>The Milange-Mocuba corridor is a strategically important road in western Zambezia Province, connecting the Malawian border at Milange with the provincial capital Quelimane via Mocuba, and passes through ecologically rich and densely populated rural areas.</p>" `
  -oPT "<p>A Enviestudos elaborou o Estudo de Impacto Ambiental e Social (EIA) para o projecto de melhoramento da estrada Milange-Mocuba na Prov&iacute;ncia da Zamb&eacute;zia, uma iniciativa financiada pela UE contratada atrav&eacute;s da BCEOM (Fran&ccedil;a). Este foi um dos primeiros projectos significativos da empresa, demonstrando capacidade em EIA abrangente e planeamento de reassentamento para grande infraestrutura.</p><p>O corredor Milange-Mocuba &eacute; uma estrada de import&acirc;ncia estrat&eacute;gica no oeste da Prov&iacute;ncia da Zamb&eacute;zia, ligando a fronteira com o Mal&aacute;ui em Milange &agrave; capital provincial Quelimane via Mocuba, e atravessa &aacute;reas rurais ecologicamente ricas e densamente povoadas.</p>" `
  -scEN "<li>Full ESIA process from Scoping Report to final approved ESIA</li><li>Terms of Reference preparation and regulatory submission</li><li>Comprehensive environmental and socioeconomic baseline surveys</li><li>Flora and fauna biodiversity assessment along the road corridor</li><li>Extensive public consultation programme in communities along the full corridor</li><li>Resettlement Action Plan (RAP) preparation for project-affected persons</li><li>ESMP preparation including environmental monitoring framework</li><li>Final ESIA Report and RAP submission to Mozambican authorities</li>" `
  -scPT "<li>Processo completo de EIA desde o Relat&oacute;rio de Delimita&ccedil;&atilde;o at&eacute; ao EIA final aprovado</li><li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia e submiss&atilde;o regulat&oacute;ria</li><li>Levantamentos abrangentes de base ambiental e socioecon&oacute;mica</li><li>Avalia&ccedil;&atilde;o de biodiversidade de flora e fauna ao longo do corredor rodovi&aacute;rio</li><li>Programa extenso de consulta p&uacute;blica nas comunidades ao longo de todo o corredor</li><li>Elabora&ccedil;&atilde;o do Plano de Ac&ccedil;&atilde;o de Reassentamento (PAR) para pessoas afectadas pelo projecto</li><li>Elabora&ccedil;&atilde;o do PGAS incluindo quadro de monitoriza&ccedil;&atilde;o ambiental</li><li>Submiss&atilde;o do Relat&oacute;rio Final de EIA e PAR &agrave;s autoridades mo&ccedil;ambicanas</li>" `
  -evEN "<li><strong>Biodiversity corridor:</strong> The Milange-Mocuba corridor crosses ecologically rich areas of Zambezia Province requiring comprehensive flora and fauna baseline assessment.</li><li><strong>Resettlement:</strong> Upgrading of the road corridor required a full Resettlement Action Plan for households and businesses affected by the road reserve.</li><li><strong>Protected area proximity:</strong> Assessment of ecological sensitivities in relation to forest reserves and protected wildlife areas near the corridor.</li><li><strong>Hydrological impacts:</strong> Numerous river crossings requiring bridge and culvert improvement with associated aquatic habitat assessments.</li>" `
  -evPT "<li><strong>Corredor de biodiversidade:</strong> O corredor Milange-Mocuba atravessa &aacute;reas ecologicamente ricas da Prov&iacute;ncia da Zamb&eacute;zia que requerem avalia&ccedil;&atilde;o abrangente de flora e fauna.</li><li><strong>Reassentamento:</strong> O melhoramento do corredor rodovi&aacute;rio exigiu um Plano de Ac&ccedil;&atilde;o de Reassentamento completo para agr&eacute;gados familiares e empresas afectadas pela reserva rodovi&aacute;ria.</li><li><strong>Proximidade de &aacute;reas protegidas:</strong> Avalia&ccedil;&atilde;o de sensibilidades ecol&oacute;gicas em rela&ccedil;&atilde;o a reservas florestais e &aacute;reas de vida selvagem protegidas pr&oacute;ximas do corredor.</li><li><strong>Impactos hidrol&oacute;gicos:</strong> Numerosas travessias fluviais que requerem melhoramento de pontes e aquedutos com avalia&ccedil;&otilde;es de habitat aqu&aacute;tico associadas.</li>" `
  -rEN "The comprehensive ESIA and RAP enabled the EU-financed Milange-Mocuba road upgrading to proceed with full environmental and resettlement approval, establishing a thorough environmental management framework that guided subsequent supervision assignments by Enviestudos on the same corridor." `
  -rPT "O EIA e PAR abrangentes permitiram que o melhoramento da estrada Milange-Mocuba financiado pela UE avan&ccedil;asse com plena aprova&ccedil;&atilde;o ambiental e de reassentamento, estabelecendo um quadro de gest&atilde;o ambiental rigoroso que orientou as subsequentes miss&otilde;es de supervis&atilde;o da Enviestudos no mesmo corredor." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-rap.html' $svgEsia 'Resettlement Planning')" `
  -rel "$(MkRc 'project-milange-lot2.html' 'Roads &amp; Bridges &bull; 2015' 'EHS Supervision &mdash; Milange-Mocuba Phase II, Lot 2' 'EHS supervision for EU-financed Milange-Mocuba Phase II works on same corridor.')$(MkRc 'project-milange-decommission.html' 'Roads &amp; Bridges &bull; 2019' 'Environmental Decommissioning &mdash; Milange-Mocuba Phase II' 'Environmental decommissioning inspection after completion of Phase II construction works.')"

# ─── Project 19: EN1 Namacurra ───
MkPage -f "project-en1-namacurra.html" -pn "19" `
  -pt "ESIA Supervision, EN1 Namacurra-Rio Ligonha, Zambezia" `
  -md "ESIA and environmental supervision for EN1 Namacurra-Rio Ligonha road rehabilitation, EU-financed — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Zambezia Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia da Zamb&eacute;zia" `
  -bc "EN1 Namacurra&ndash;Rio Ligonha Supervision" -yr "2005&ndash;2008" -prov "Zambezia" `
  -cl "BCEOM, France" -fund "European Union" -sec "Roads &amp; Bridges" `
  -svd "ESIA &bull; Supervision &bull; ESMP Monitoring &bull; Final Report" `
  -tgs '<span class="project-tag">EU</span><span class="project-tag">Supervision</span><span class="project-tag">EN1</span><span class="project-tag">Zambezia</span><span class="project-tag">ESIA</span>' `
  -oEN "<p>Enviestudos provided ESIA preparation and multi-year environmental supervision services for the rehabilitation of Road EN1 between Namacurra and Rio Ligonha in Zambezia Province, one of Mozambique&rsquo;s primary north-south road corridors. The project was financed by the European Union and contracted through BCEOM (France).</p><p>This was one of Enviestudos&rsquo; founding projects, spanning three years of environmental supervision throughout the construction period — establishing the firm&rsquo;s reputation for sustained, high-quality environmental supervision on major EU-financed road projects in Mozambique.</p>" `
  -oPT "<p>A Enviestudos prestou servi&ccedil;os de elabora&ccedil;&atilde;o de EIA e supervis&atilde;o ambiental plurianual para a reabilita&ccedil;&atilde;o da Estrada EN1 entre Namacurra e o Rio Ligonha na Prov&iacute;ncia da Zamb&eacute;zia, um dos principais corredores rodovi&aacute;rios norte-sul de Mo&ccedil;ambique. O projecto foi financiado pela Uni&atilde;o Europeia e contratado atrav&eacute;s da BCEOM (Fran&ccedil;a).</p><p>Este foi um dos projectos fundadores da Enviestudos, abrangendo tr&ecirc;s anos de supervis&atilde;o ambiental durante todo o per&iacute;odo de constru&ccedil;&atilde;o &mdash; estabelecendo a reputa&ccedil;&atilde;o da empresa pela supervis&atilde;o ambiental sustentada e de alta qualidade em grandes projectos rodovi&aacute;rios financiados pela UE em Mo&ccedil;ambique.</p>" `
  -scEN "<li>ESIA preparation including Scoping Report, ToR, baseline surveys, and impact assessment</li><li>Public consultation programme along the Namacurra&ndash;Rio Ligonha corridor</li><li>Full ESIA Report preparation and regulatory submission</li><li>Environmental monitoring programme implementation throughout the three-year construction period</li><li>Periodic environmental compliance reporting to the EU and Mozambican authorities</li><li>Non-conformance tracking and corrective action monitoring</li><li>Final environmental compliance report at project completion</li>" `
  -scPT "<li>Elabora&ccedil;&atilde;o de EIA incluindo Relat&oacute;rio de Delimita&ccedil;&atilde;o, ToR, levantamentos de base e avalia&ccedil;&atilde;o de impacto</li><li>Programa de consulta p&uacute;blica ao longo do corredor Namacurra&ndash;Rio Ligonha</li><li>Elabora&ccedil;&atilde;o do Relat&oacute;rio Final de EIA e submiss&atilde;o regulat&oacute;ria</li><li>Implementa&ccedil;&atilde;o do programa de monitoriza&ccedil;&atilde;o ambiental ao longo do per&iacute;odo de constru&ccedil;&atilde;o de tr&ecirc;s anos</li><li>Relato peri&oacute;dico de conformidade ambiental para a UE e autoridades mo&ccedil;ambicanas</li><li>Registo de n&atilde;o-conformidades e monitoriza&ccedil;&atilde;o de ac&ccedil;&otilde;es correctivas</li><li>Relat&oacute;rio final de conformidade ambiental na conclus&atilde;o do projecto</li>" `
  -evEN "<li><strong>Primary road corridor ecology:</strong> Ecological baseline of the EN1 corridor in Zambezia Province, including agricultural land, river crossings, and rural community interface zones.</li><li><strong>Rio Ligonha crossing:</strong> Major river crossing environmental assessment and protection measures for the Ligonha River aquatic ecosystem.</li><li><strong>Construction monitoring:</strong> Three years of ESMP implementation monitoring including borrow pits, camps, spoil management, and drainage.</li><li><strong>Community relations:</strong> Three-year community liaison programme supporting affected communities along the road corridor.</li>" `
  -evPT "<li><strong>Ecologia do corredor rodovi&aacute;rio principal:</strong> Base ecol&oacute;gica do corredor EN1 na Prov&iacute;ncia da Zamb&eacute;zia, incluindo terra agr&iacute;cola, travessias fluviais e zonas de interface com comunidades rurais.</li><li><strong>Travessia do Rio Ligonha:</strong> Avalia&ccedil;&atilde;o ambiental da travessia fluvial principal e medidas de prote&ccedil;&atilde;o do ecossistema aqu&aacute;tico do Rio Ligonha.</li><li><strong>Monitoriza&ccedil;&atilde;o da constru&ccedil;&atilde;o:</strong> Tr&ecirc;s anos de monitoriza&ccedil;&atilde;o da implementa&ccedil;&atilde;o do PGAS incluindo zonas de empr&eacute;stimo, acampamentos, gest&atilde;o de excedentes e drenagem.</li><li><strong>Rela&ccedil;&otilde;es comunit&aacute;rias:</strong> Programa de liga&ccedil;&atilde;o comunit&aacute;ria de tr&ecirc;s anos de apoio &agrave;s comunidades afectadas ao longo do corredor rodovi&aacute;rio.</li>" `
  -rEN "The three-year ESIA supervision assignment for the EN1 Namacurra&ndash;Rio Ligonha rehabilitation established Enviestudos as a reliable partner for long-term environmental supervision of major EU-financed infrastructure projects in Mozambique, and contributed to full environmental compliance throughout the construction works." `
  -rPT "A miss&atilde;o de supervis&atilde;o de EIA de tr&ecirc;s anos para a reabilita&ccedil;&atilde;o da EN1 Namacurra&ndash;Rio Ligonha estabeleceu a Enviestudos como parceiro de confiança para a supervis&atilde;o ambiental de longa dura&ccedil;&atilde;o de grandes projectos de infraestrutura financiados pela UE em Mo&ccedil;ambique, contribuindo para a plena conformidade ambiental durante as obras de constru&ccedil;&atilde;o." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')" `
  -rel "$(MkRc 'project-en1-vilanculos.html' 'Roads &amp; Bridges &bull; 2002' 'ESMP &mdash; EN1, Nhachengue&ndash;Vilanculos, Inhambane' 'ESMP for EU-financed EN1 rehabilitation in Inhambane Province &mdash; founding Enviestudos project.')$(MkRc 'project-milange-esia.html' 'Roads &amp; Bridges &bull; 2007&ndash;2008' 'ESIA &mdash; Milange&ndash;Mocuba Road Upgrading' 'Comprehensive ESIA for EU-financed road upgrading in Zambezia Province, prepared for BCEOM.')"

# ─── Project 20: EN1 Vilanculos ───
MkPage -f "project-en1-vilanculos.html" -pn "20" `
  -pt "ESMP, Road EN1 Nhachengue-Vilanculos, Inhambane Province" `
  -md "ESMP for EU-financed Road EN1 rehabilitation, Nhachengue to Vilanculos, Inhambane Province — Enviestudos founding project." `
  -hlEN "Roads &amp; Bridges &bull; Inhambane Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia de Inhambane" `
  -bc "EN1 Nhachengue&ndash;Vilanculos ESMP" -yr "2002" -prov "Inhambane" `
  -cl "Austral Consultoria &amp; WSP-MBS" -fund "European Union" -sec "Roads &amp; Bridges" `
  -svd "ESMP &bull; Public Consultations &bull; Environmental Supervision" `
  -tgs '<span class="project-tag">EU</span><span class="project-tag">ESMP</span><span class="project-tag">EN1</span><span class="project-tag">Inhambane</span><span class="project-tag">Founding Project</span>' `
  -oEN "<p>The EN1 Nhachengue-Vilanculos ESMP was one of the founding projects of Enviestudos in 2002 &mdash; prepared for Austral Consultoria and WSP-MBS for the EU-financed rehabilitation of the EN1 national road between Nhachengue and Vilanculos in Inhambane Province. This project marked the beginning of Enviestudos&rsquo; track record in environmental management planning for major road projects.</p><p>The EN1 corridor in this section traverses the coastal lowlands of Inhambane Province, approaching the important tourism and fishing town of Vilanculos, and passes through communities whose livelihoods depend on both agriculture and coastal fisheries.</p>" `
  -oPT "<p>O PGAS EN1 Nhachengue-Vilanculos foi um dos projectos fundadores da Enviestudos em 2002 &mdash; preparado para a Austral Consultoria e WSP-MBS para a reabilita&ccedil;&atilde;o financiada pela UE da estrada nacional EN1 entre Nhachengue e Vilanculos na Prov&iacute;ncia de Inhambane. Este projecto marcou o in&iacute;cio do historial da Enviestudos em planeamento de gest&atilde;o ambiental para grandes projectos rodovi&aacute;rios.</p><p>O corredor EN1 nesta sec&ccedil;&atilde;o atravessa as baixas costeiras da Prov&iacute;ncia de Inhambane, aproximando-se da importante cidade de turismo e pesca de Vilanculos, e passa por comunidades cujos meios de subsist&ecirc;ncia dependem tanto da agricultura como da pesca costeira.</p>" `
  -scEN "<li>Environmental Simplified Study (ESS) preparation for the EN1 road section</li><li>Baseline environmental and socioeconomic surveys along the road corridor</li><li>Public consultation meetings with communities along the Nhachengue&ndash;Vilanculos section</li><li>Environmental Management Plan (ESMP) preparation for road rehabilitation works</li><li>Construction-phase environmental management provisions and monitoring programme</li><li>Environmental supervision support during road rehabilitation construction works</li>" `
  -scPT "<li>Elabora&ccedil;&atilde;o do Estudo Ambiental Simplificado (EAS) para o troço de estrada EN1</li><li>Levantamentos de base ambiental e socioecon&oacute;mica ao longo do corredor rodovi&aacute;rio</li><li>Reuni&otilde;es de consulta p&uacute;blica com as comunidades ao longo do troço Nhachengue&ndash;Vilanculos</li><li>Elabora&ccedil;&atilde;o do Plano de Gest&atilde;o Ambiental e Social (PGAS) para obras de reabilita&ccedil;&atilde;o rodovi&aacute;ria</li><li>Disposi&ccedil;&otilde;es de gest&atilde;o ambiental na fase de constru&ccedil;&atilde;o e programa de monitoriza&ccedil;&atilde;o</li><li>Apoio de supervis&atilde;o ambiental durante as obras de constru&ccedil;&atilde;o da reabilita&ccedil;&atilde;o rodovi&aacute;ria</li>" `
  -evEN "<li><strong>Coastal proximity:</strong> Environmental sensitivity of the Inhambane coastal zone near Vilanculos, including marine and estuarine habitats affected by road construction.</li><li><strong>Fisheries and livelihoods:</strong> Coastal fishing community livelihoods and access to fishing grounds potentially affected by the road rehabilitation works.</li><li><strong>Tourism environment:</strong> Environmental protection considerations for the growing coastal tourism environment around Vilanculos.</li><li><strong>Drainage management:</strong> Construction-phase drainage management in the flat coastal lowlands susceptible to flooding and drainage disturbance.</li>" `
  -evPT "<li><strong>Proximidade costeira:</strong> Sensibilidade ambiental da zona costeira de Inhambane pr&oacute;ximo de Vilanculos, incluindo habitats marinhos e estuarinos afectados pela constru&ccedil;&atilde;o rodovi&aacute;ria.</li><li><strong>Pesca e meios de subsist&ecirc;ncia:</strong> Meios de subsist&ecirc;ncia das comunidades de pesca costeira e acesso a &aacute;reas de pesca potencialmente afectados pelas obras de reabilita&ccedil;&atilde;o rodovi&aacute;ria.</li><li><strong>Ambiente do turismo:</strong> Considera&ccedil;&otilde;es de prote&ccedil;&atilde;o ambiental para o crescente ambiente de turismo costeiro em torno de Vilanculos.</li><li><strong>Gest&atilde;o da drenagem:</strong> Gest&atilde;o da drenagem na fase de constru&ccedil;&atilde;o nas baixas costeiras planas suscept&iacute;veis a inunda&ccedil;&otilde;es e perturba&ccedil;&otilde;es de drenagem.</li>" `
  -rEN "As one of Enviestudos&rsquo; founding projects, the EN1 Nhachengue-Vilanculos ESMP established the firm&rsquo;s approach to environmental management planning for EU-financed road projects, laying the foundation for over two decades of environmental consulting in Mozambique&rsquo;s infrastructure sector." `
  -rPT "Como um dos projectos fundadores da Enviestudos, o PGAS EN1 Nhachengue-Vilanculos estabeleceu a abordagem da empresa ao planeamento de gest&atilde;o ambiental para projectos rodovi&aacute;rios financiados pela UE, lan&ccedil;ando as bases para mais de duas d&eacute;cadas de consultoria ambiental no sector de infraestruturas de Mo&ccedil;ambique." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-en1-namacurra.html' 'Roads &amp; Bridges &bull; 2005&ndash;2008' 'ESIA Supervision &mdash; EN1, Namacurra&ndash;Rio Ligonha' 'Three-year ESIA and supervision for EU-financed EN1 rehabilitation in Zambezia Province.')$(MkRc 'project-beira.html' 'Infrastructure &bull; 2019&ndash;2021' 'ESIA &mdash; Beira Corridor Road Rehabilitation' 'ESIA for rehabilitation of the strategic Beira road corridor in Sofala Province.')"

